import java.util.*;

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int[] nums = new int[n];
        for (int i = 0; i < n; i++) {
            nums[i] = scanner.nextInt();
        }

        int write = 0;
        for (int num : nums) {
            if (num != 0) {
                nums[write++] = num;
            }
        }
        while (write < n) {
            nums[write++] = 0;
        }

        StringBuilder output = new StringBuilder();
        for (int i = 0; i < n; i++) {
            if (i > 0) {
                output.append(' ');
            }
            output.append(nums[i]);
        }
        System.out.println(output);
    }
}
